function compact(value, maxLen = 1200) {
  const v = String(value || '').replace(/\s+/g, ' ').trim();
  return v.length > maxLen ? v.slice(0, maxLen) : v;
}

function normalizeUrl(url) {
  const u = String(url || '').trim();
  if (!u || u === 'undefined' || u === 'null') return null;
  return u;
}

function normalizeAddress(line1, postalCode, cityName) {
  const parts = [line1, postalCode, cityName]
    .map(v => String(v || '').trim())
    .filter(Boolean);
  return parts.length ? parts.join(', ') : null;
}

const item = $json;
const entityType = item.entity_type;
const entityExists = entityType === 'event' ? !!item.event_id : !!item.place_id;

let aiInput = null;
if (entityExists && entityType === 'event') {
  aiInput = {
    title: compact(item.title, 200),
    description_de: compact(item.description_de, 1500),
    category: item.category || null,
    city_id: item.event_city_id || null,
    city_name: item.event_city_name || null,
    venue_name: compact(item.venue_name, 200),
    starts_at: item.starts_at || null,
    organizer_name: compact(item.organizer_name, 200),
    external_url: normalizeUrl(item.external_url)
  };
}

if (entityExists && entityType === 'place') {
  aiInput = {
    name: compact(item.name, 180),
    description_de: compact(item.place_description_de, 1400),
    category_id: item.category_id || null,
    category_name: item.category_name || null,
    city_id: item.place_city_id || null,
    city_name: item.place_city_name || null,
    address_line_1: compact(item.address_line_1, 200),
    postal_code: compact(item.postal_code, 20),
    address_compact: normalizeAddress(item.address_line_1, item.postal_code, item.place_city_name),
    latitude: item.latitude ?? null,
    longitude: item.longitude ?? null,
    website_url: normalizeUrl(item.website_url),
    phone: compact(item.phone, 80)
  };
}

return {
  json: {
    request_id: item.request_id,
    requested_by_user_id: item.requested_by_user_id,
    entity_type: entityType,
    entity_id: item.entity_id,
    model_name: 'gemini-2.5-flash',
    entity_exists: entityExists,
    ai_input: aiInput,
    worker_error: entityExists ? null : 'ENTITY_NOT_FOUND',
    retry_attempt: item.retry_attempt ?? 0,
    max_retries: 2,
    provider_error_code: null,
    should_retry: false,
    retry_delay_seconds: 0
  }
};

