function normalizeWhitespace(value) {
  return String(value || '').replace(/\s+/g, ' ').trim();
}

function clamp01(value) {
  if (typeof value !== 'number' || !Number.isFinite(value)) return null;
  if (value < 0) return 0;
  if (value > 1) return 1;
  return value;
}

function normalizeStatus(raw) {
  const value = normalizeWhitespace(raw).toUpperCase();

  const map = {
    OK: 'OK',
    REVIEW: 'REVIEW',
    UNSURE: 'UNSURE',
    REJECT: 'REJECT',

    APPROVE: 'OK',
    APPROVED: 'OK',
    KEEP: 'OK',

    MANUAL_REVIEW: 'REVIEW',
    'MANUAL REVIEW': 'REVIEW',
    REVIEW_NEEDED: 'REVIEW',
    'REVIEW NEEDED': 'REVIEW',
    FLAGGED: 'REVIEW',

    UNKNOWN: 'UNSURE',
    LOW_CONFIDENCE: 'UNSURE',
    'LOW CONFIDENCE': 'UNSURE',
    AMBIGUOUS: 'UNSURE',

    REJECTED: 'REJECT',
    BLOCK: 'REJECT',
  };

  return map[value] || 'UNSURE';
}

function normalizeSuggestedAction(raw) {
  if (raw == null) return null;

  const value = normalizeWhitespace(raw).toUpperCase();

  const map = {
    OK: 'OK',
    REVIEW: 'REVIEW',
    UNSURE: 'UNSURE',
    REJECT: 'REJECT',

    KEEP: 'OK',
    SEND_TO_MODERATION: 'REVIEW',
    'SEND TO MODERATION': 'REVIEW',
    REVIEW_MANUALLY: 'REVIEW',
    'REVIEW MANUALLY': 'REVIEW',
    REJECTED: 'REJECT',
  };

  return map[value] || null;
}

function normalizeConfidence(raw) {
  if (raw == null) return null;

  if (typeof raw === 'number') {
    return clamp01(raw);
  }

  if (typeof raw === 'string') {
    const parsed = Number(raw);
    if (Number.isFinite(parsed)) {
      return clamp01(parsed);
    }
  }

  return null;
}

function normalizeReasonCodes(raw) {
  let arr = [];

  if (Array.isArray(raw)) {
    arr = raw.filter(v => typeof v === 'string');
  } else if (typeof raw === 'string') {
    arr = [raw];
  } else {
    return [];
  }

  const cleaned = arr
    .map(v => normalizeWhitespace(v))
    .filter(Boolean)
    .map(v => v.toUpperCase().replace(/\s+/g, '_'))
    .slice(0, 10);

  return [...new Set(cleaned)];
}

function normalizeExplanation(raw) {
  if (typeof raw !== 'string') return null;
  const value = normalizeWhitespace(raw);
  if (!value) return null;
  return value.slice(0, 2000);
}

function extractRawText(input) {
  if (typeof input?.raw_text === 'string' && input.raw_text.trim()) {
    return input.raw_text.trim();
  }

  if (typeof input?.data === 'string' && input.data.trim()) {
    return input.data.trim();
  }

  const responseBody = input?.body ?? input?.data ?? input;
  const geminiText =
    responseBody?.candidates?.[0]?.content?.parts?.[0]?.text;

  if (typeof geminiText === 'string' && geminiText.trim()) {
    return geminiText.trim();
  }

  return null;
}

function tryParseJson(rawText) {
  if (!rawText || typeof rawText !== 'string' || !rawText.trim()) {
    return { ok: false, error: 'empty_response', parsed: null };
  }

  try {
    return { ok: true, error: null, parsed: JSON.parse(rawText) };
  } catch (e) {}

  const firstBrace = rawText.indexOf('{');
  const lastBrace = rawText.lastIndexOf('}');
  if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
    const candidate = rawText.slice(firstBrace, lastBrace + 1);
    try {
      return { ok: true, error: null, parsed: JSON.parse(candidate) };
    } catch (e) {}
  }

  return { ok: false, error: 'invalid_json', parsed: null };
}

function extractPayload(parsed) {
  if (!parsed || typeof parsed !== 'object') return {};

  const nestedText = parsed?.candidates?.[0]?.content?.parts?.[0]?.text;
  if (typeof nestedText === 'string' && nestedText.trim()) {
    try {
      return JSON.parse(nestedText);
    } catch {
      return parsed;
    }
  }

  return parsed;
}

const item = $json;
const rawText = extractRawText(item);

if (!rawText) {
  return {
    json: {
      request_id: item.request_id || null,
      entity_type: item.entity_type || null,
      entity_id: item.entity_id || null,
      model_name: item.model_name || 'gemini-2.5-flash',
      raw_result_json: null,
      normalized_result: null,
      normalization_error: 'empty_response',
      provider_error: null,
      should_fail_request: true
    }
  };
}

const parsedAttempt = tryParseJson(rawText);

if (!parsedAttempt.ok) {
  return {
    json: {
      request_id: item.request_id || null,
      entity_type: item.entity_type || null,
      entity_id: item.entity_id || null,
      model_name: item.model_name || 'gemini-2.5-flash',
      raw_result_json: rawText,
      normalized_result: null,
      normalization_error: parsedAttempt.error || 'invalid_json',
      provider_error: null,
      should_fail_request: true
    }
  };
}

const payload = extractPayload(parsedAttempt.parsed);

const rawStatus = payload.ai_status ?? payload.status ?? null;
const rawConfidence = payload.confidence_score ?? payload.confidence ?? null;
const rawReasonCodes = payload.reason_codes ?? [];
const rawExplanation = payload.explanation ?? payload.notes ?? null;
const rawSuggestedAction = payload.suggested_action ?? null;

const normalized = {
  ai_status: normalizeStatus(rawStatus),
  confidence_score: normalizeConfidence(rawConfidence),
  reason_codes: normalizeReasonCodes(rawReasonCodes),
  explanation: normalizeExplanation(rawExplanation),
  suggested_action: normalizeSuggestedAction(rawSuggestedAction)
};

return {
  json: {
    request_id: item.request_id || null,
    entity_type: item.entity_type || null,
    entity_id: item.entity_id || null,
    model_name: item.model_name || 'gemini-2.5-flash',
    raw_result_json: JSON.stringify(payload),
    normalized_result: normalized,
    normalization_error: null,
    provider_error: null,
    should_fail_request: false,

    ai_status: normalized.ai_status,
    confidence_score: normalized.confidence_score,
    reason_codes_json: JSON.stringify(normalized.reason_codes),
    explanation: normalized.explanation,
    suggested_action: normalized.suggested_action
  }
};

function decodeBufferObject(obj) {
  if (!obj) return null;

  if (obj.type === "Buffer" && Array.isArray(obj.data)) {
    try {
      return Buffer.from(obj.data).toString("utf8");
    } catch {
      return null;
    }
  }

  if (typeof obj === "object") {
    for (const key of Object.keys(obj)) {
      const result = decodeBufferObject(obj[key]);
      if (result) return result;
    }
  }

  return null;
}

const existingRawText =
  typeof $json.raw_text === "string" && $json.raw_text.trim()
    ? $json.raw_text.trim()
    : null;

const decoded = existingRawText || decodeBufferObject($json);

return {
  json: {
    ...$json,
    raw_text: decoded
  }
};

function getStatusCode(json) {
  const candidates = [
    json.statusCode,
    json.status,
    json.response?.statusCode,
    json.response?.status,
    json.body?.status,
    json.error?.statusCode,
    json.error?.status,
    json.provider_status_code,
  ];

  for (const value of candidates) {
    const num = Number(value);
    if (Number.isFinite(num)) return num;
  }

  return null;
}

function getErrorText(json) {
  const candidates = [
    json.error,
    json.message,
    json.statusMessage, 
    json.body?.error?.message,
    json.body?.message,
    json.response?.body?.error?.message,
    json.response?.body?.message,
    json.code,
  ];

  for (const value of candidates) {
    if (typeof value === 'string' && value.trim()) return value.trim();

    if (value && typeof value.message === 'string' && value.message.trim()) {
      return value.message.trim();
    }
  }

  return null;
}

function detectTimeout(json, errorText) {
  const code = String(json.code || json.error?.code || '').toUpperCase();
  const text = String(errorText || '').toLowerCase();

  return (
    code.includes('TIMEOUT') ||
    code === 'ECONNABORTED' ||
    text.includes('timeout') ||
    text.includes('timed out') ||
    text.includes('deadline exceeded') ||
    text.includes('socket hang up')
  );
}

function isProviderSuccess(json, statusCode, errorText) {
  if (statusCode !== null) {
    return statusCode >= 200 && statusCode < 300;
  }

  if (json.body?.candidates || json.candidates || json.raw_text) {
    return true;
  }

  if (errorText) {
    return false;
  }

  return false;
}

return items.map((item) => {
  const json = item.json;
  const retryAttempt = Number(json.retry_attempt ?? 0) || 0;
  const statusCode = getStatusCode(json);
  const errorText = getErrorText(json);
  const timeoutDetected = detectTimeout(json, errorText);

  let providerSuccess = isProviderSuccess(json, statusCode, errorText);
  let providerErrorCode = null;
  let shouldRetry = false;
  let retryDelaySeconds = 0;

  if (!providerSuccess) {
    const is429 = statusCode === 429;
    const is5xx = statusCode !== null && statusCode >= 500 && statusCode <= 599;
    const isTimeout = timeoutDetected;

    if (is429) {
      providerErrorCode = 'provider_rate_limit';
      shouldRetry = retryAttempt < 2;
    } else if (isTimeout) {
      providerErrorCode = 'provider_timeout';
      shouldRetry = retryAttempt < 2;
    } else if (is5xx) {
      providerErrorCode = 'provider_http_error';
      shouldRetry = retryAttempt < 2;
    } else {
      providerErrorCode = 'provider_http_error';
      shouldRetry = false;
    }

    if (shouldRetry) {
      retryDelaySeconds = retryAttempt === 0 ? 10 : 30;
    }
  }

  return {
    json: {
      ...json,
      provider_success: providerSuccess,
      provider_status_code: statusCode,
      provider_error_code: providerErrorCode,
      provider_error_text: errorText,
      should_retry: shouldRetry,
      retry_delay_seconds: retryDelaySeconds,
      retry_attempt: retryAttempt,
      final_provider_failure: !providerSuccess && !shouldRetry,
    },
  };
});

return items.map((item) => {
  const json = { ...item.json };

  delete json.body;
  delete json.headers;
  delete json.statusCode;
  delete json.statusMessage;
  delete json.error;
  delete json.code;
  delete json.raw_text;
  delete json.raw_result_json;
  delete json.normalized_result;
  delete json.normalization_error;

  return {
    json: {
      ...json,
      retry_attempt: (Number(json.retry_attempt ?? 0) || 0) + 1,
      should_retry: false,
      retry_delay_seconds: 0,
      provider_error_code: null,
      provider_error_text: null,
      provider_success: false,
      provider_status_code: null,
      final_provider_failure: false,
    },
  };
});
